import {
  NormalizedOpenApiValidatorOpts,
  Options,
  RequestValidatorOptions,
  ValidateRequestOpts,
  ValidateResponseOpts,
} from '../types';

export class AjvOptions {
  private options: NormalizedOpenApiValidatorOpts;
  constructor(options: NormalizedOpenApiValidatorOpts) {
    this.options = options;
  }

  get preprocessor(): Options {
    return this.baseOptions();
  }

  get response(): Options {
    const { allErrors, coerceTypes, removeAdditional } = <ValidateResponseOpts>(
      this.options.validateResponses
    );
    return {
      ...this.baseOptions(),
      allErrors,
      useDefaults: false,
      coerceTypes,
      removeAdditional,
    };
  }

  get request(): RequestValidatorOptions {
    const { allErrors, allowUnknownQueryParameters, coerceTypes, removeAdditional, discriminator } = <
      ValidateRequestOpts
    >this.options.validateRequests;
    return {
      ...this.baseOptions(),
      allErrors,
      allowUnknownQueryParameters,
      coerceTypes,
      removeAdditional,
      discriminator,
    };
  }

  get multipart(): Options {
    return this.baseOptions();
  }

  private baseOptions(): Options {
    const {
      coerceTypes,
      formats,
      validateFormats,
      serDes,
      ajvFormats,
    } = this.options;
    const serDesMap = {};
    for (const serDesObject of serDes) {
      if (!serDesMap[serDesObject.format]) {
        serDesMap[serDesObject.format] = serDesObject;
      } else {
        if (serDesObject.serialize) {
          serDesMap[serDesObject.format].serialize = serDesObject.serialize;
        }
        if (serDesObject.deserialize) {
          serDesMap[serDesObject.format].deserialize = serDesObject.deserialize;
        }
      }
    }

    const options: Options = {
      strict: false,
      strictNumbers: true,
      strictTuples: true,
      allowUnionTypes: false,
      validateSchema: false, // this is true for startup validation, thus it can be bypassed here
      coerceTypes,
      useDefaults: true,
      removeAdditional: false,
      validateFormats,
      formats,
      serDesMap,
      ajvFormats,
    };

    return options;
  }
}

import uniq from 'lodash/uniq.js';
import { EMPTY_ARRAY } from '../consts.js';
import type { Entry, MapLike } from '../types.js';

export class MultiMap<K, V> implements MapLike<K, readonly V[]> {
  readonly #internalMap = new Map<K, readonly V[]>();

  constructor(entries?: Iterable<readonly [K, readonly V[]]>) {
    if (entries) {
      for (const [key, values] of entries) {
        this.set(key, values);
      }
    }
  }

  get size() {
    return this.#internalMap.size;
  }

  clear() {
    this.#internalMap.clear();
  }

  append(key: K, value: V): this {
    const valueSet = this.#internalMap.get(key);
    if (valueSet?.includes(value)) {
      return this;
    }

    const newValue = valueSet ? [...valueSet, value] : [value];
    Object.freeze(newValue);

    this.#internalMap.set(key, newValue);

    return this;
  }

  deleteValue(key: K, value: V): boolean {
    const valueSet = this.#internalMap.get(key);
    if (valueSet == null) {
      return false;
    }

    const newValueSet = valueSet.filter(val => val !== value);
    if (newValueSet.length === valueSet.length) {
      return false;
    }

    if (newValueSet.length === 0) {
      this.#internalMap.delete(key);

      return true;
    }

    Object.freeze(newValueSet);
    this.#internalMap.set(key, newValueSet);

    return true;
  }

  delete(key: K): boolean {
    return this.#internalMap.delete(key);
  }

  keys(): IterableIterator<K> {
    return this.#internalMap.keys();
  }

  count(key: K): number {
    const values = this.#internalMap.get(key);

    return values?.length ?? 0;
  }

  [Symbol.iterator](): IterableIterator<Entry<K, readonly V[]>> {
    return this.#internalMap[Symbol.iterator]();
  }

  entries(): IterableIterator<Entry<K, readonly V[]>> {
    return this.#internalMap.entries();
  }

  get(key: K): readonly V[] {
    return this.#internalMap.get(key) ?? EMPTY_ARRAY;
  }

  has(key: K): boolean {
    return this.#internalMap.has(key);
  }

  set(key: K, values: readonly V[]): this {
    if (values.length === 0) {
      this.#internalMap.delete(key);

      return this;
    }

    const uniqueValues = Object.freeze(uniq(values));

    this.#internalMap.set(key, uniqueValues);

    return this;
  }

  values(): IterableIterator<readonly V[]> {
    return this.#internalMap.values();
  }
}

import {configuration, constant, injectable, logger} from "@tsed/di";
import {$off, $on, $once} from "@tsed/hooks";

import {CONFIG_SOURCES} from "../constants/constants.js";
import type {ConfigurationExtends} from "../interfaces/ConfigSource.js";
import {getConfigSources} from "../utils/getConfigSources.js";
import {validate} from "../utils/validate.js";

export async function afterResolveConfiguration() {
  const sources = getConfigSources(constant<ConfigurationExtends>("extends", []));

  for (const source of sources.values()) {
    const {instance, watch, refreshOn, name, validationSchema} = source;
    const seed = Math.floor(Math.random() * 10000);
    const ref = name + "-" + seed;

    if (instance?.$onInit) {
      await instance.$onInit();
    }

    const getAll = instance.getAll;

    const refresh = async () => {
      let data = await getAll.apply(instance);

      if (validationSchema) {
        const {validate} = await import("../utils/validate.js");
        data = validate(name!, data, validationSchema);
      }

      configuration().set(data);
      configuration().set(`configs.${name}`, data);
    };

    instance.getAll = refresh as any;

    await refresh();

    // manage watcher
    if (watch && instance?.watch) {
      const closer = await instance.watch(refresh);

      closer && $once("$onDestroy", ref, closer);
    }

    // manager refresh on request
    if (refreshOn === "request") {
      $on("$onRequest", ref, refresh);
    }

    // manager refresh on response
    if (refreshOn === "response") {
      const onResponse = () => {
        refresh().catch((error) => {
          logger().error({
            event: "CONFIG_SOURCE_REFRESH_ERROR",
            hook: "$onResponse",
            error_name: error.name,
            error_message: error.message,
            error_stack: error.stack
          });
        });
      };

      $on("$onResponse", ref, onResponse);
    }

    $once("$onDestroy", ref, () => {
      if (instance?.$onDestroy) {
        // clean all event related to the same ref
        $off(ref);

        return instance.$onDestroy();
      }
    });
  }

  const configs = Object.fromEntries(
    [...sources.entries()].map(([key, source]) => {
      return [key, source.instance];
    })
  );

  injectable(CONFIG_SOURCES).value(configs);
}

$on("$afterResolveConfiguration", afterResolveConfiguration);

import {cache, getCachedEngine, importEngine, read, readPartials} from "../utils/cache.js";

export interface ViewEngineOptions {
  requires?: string | string[];
}

export interface EngineOptions {
  cache?: boolean;

  [otherOptions: string]: any;
}

export class Engine {
  protected driverName = "";

  constructor(
    readonly name: string,
    readonly options: ViewEngineOptions
  ) {}

  get engine(): any {
    return getCachedEngine(this.name);
  }

  async $onInit() {
    await this.importEngine(this.name, this.options);
  }

  compile(template: string, options: EngineOptions) {
    options = this.$cacheOptions(template, options, false);

    return cache(options) || cache(options, this.$compile.call(this, template, options));
  }

  compileFile(file: string, options: EngineOptions) {
    options = this.$cacheOptions(file, options, true);

    return cache(options) || cache(options, this.$compileFile.call(this, file, options));
  }

  async render(template: string, options: EngineOptions) {
    const compile = await this.compile(template, options);

    return compile(options);
  }

  async renderFile(file: string, options: EngineOptions) {
    const opts = await this.readPartials(file, options);
    const compile = await this.compileFile(file, opts);

    return compile(opts);
  }

  protected async readPartials(file: string, options: EngineOptions) {
    options.filename = file;
    const partials = await readPartials(file, options);

    const opts = Object.assign({}, options);
    opts.partials = partials;

    return opts;
  }

  protected $cacheOptions(template: string, options: EngineOptions, fromFile?: boolean) {
    return options;
  }

  protected $compile(template: string, options: EngineOptions): (options: EngineOptions) => Promise<string> {
    return this.engine.compile(template, options);
  }

  protected async $compileFile(file: string, options: EngineOptions) {
    const template = await read(file, options);
    return this.$compile(template, options);
  }

  protected async importEngine(name: string, options: ViewEngineOptions) {
    const reqs = ([] as string[]).concat(options.requires || [name]);

    for (const req of reqs) {
      try {
        await importEngine(req, name);
        this.driverName = req;
      } catch {
        // silently ignore unavailable drivers while probing engine candidates
      }
    }
  }
}

import path from "node:path";

import {Project, Scope} from "ts-morph";

import {resolveExtension} from "./resolveExtension.js";

export function generatePrismaService(project: Project, baseDirPath: string) {
  const directory = project.createDirectory(path.resolve(baseDirPath, "services"));
  const prismaServiceFile = directory.createSourceFile("PrismaService.ts", "", {overwrite: true});

  prismaServiceFile.addImportDeclarations([
    {
      moduleSpecifier: "@tsed/di",
      namedImports: ["Inject", "Injectable", "Configuration", "OnInit", "OnDestroy"]
    },
    {
      moduleSpecifier: "@tsed/logger",
      namedImports: ["Logger"]
    },
    {
      moduleSpecifier: resolveExtension("../client/index"),
      namedImports: ["PrismaClient"]
    }
  ]);

  const prismaService = prismaServiceFile.addClass({
    name: "PrismaService",
    isExported: true,
    decorators: [
      {
        name: "Injectable",
        arguments: []
      }
    ],
    extends: "PrismaClient",
    implements: ["OnInit", "OnDestroy"]
  });

  prismaService.addProperty({
    name: "logger",
    scope: Scope.Protected,
    type: "Logger",
    decorators: [
      {
        name: "Inject",
        arguments: []
      }
    ]
  });

  prismaService
    .addConstructor({
      parameters: [
        {
          name: "settings",
          type: "Configuration",
          decorators: [
            {
              name: "Configuration",
              arguments: []
            }
          ]
        }
      ]
    })
    .setBodyText("super(settings.get('prisma'));");

  prismaService
    .addMethod({
      name: "$onInit",
      isAsync: true,
      returnType: "Promise<void>"
    })
    .setBodyText(
      `this.logger.info("Connection to prisma database");
      await this.$connect();`
    );

  prismaService
    .addMethod({
      name: "$onDestroy",
      isAsync: true,
      returnType: "Promise<void>"
    })
    .setBodyText(
      `this.logger.info("Disconnection from prisma database");
      await this.$disconnect();`
    );

  return prismaService;
}

import {EventEmitter} from "node:events";

import cookie from "cookie";

export class FakeResponse extends EventEmitter {
  headers: Record<string, unknown> = {};
  locals: Record<string, unknown> = {};
  statusCode: number = 200;
  data: any;

  constructor(opts = {}) {
    super();

    Object.assign(this, opts);
  }

  append(field: string, val: string | string[]) {
    const prev = this.get(field);
    let value = val;

    if (prev) {
      // concat the new and prev vals
      value = Array.isArray(prev) ? prev.concat(val) : Array.isArray(val) ? [prev].concat(val) : [prev, val];
    }

    return this.set(field, value);
  }

  status(code: number) {
    this.statusCode = code;
    return this;
  }

  contentType(content: string) {
    this.set("content-type", content);
  }

  contentLength(content: number) {
    this.set("content-length", content);
  }

  cookie(name: string, value: string, options?: TsED.SetCookieOpts) {
    const opts = {...options};

    const val = typeof value === "object" ? "j:" + JSON.stringify(value) : String(value);

    if (opts.maxAge != null) {
      const maxAge = opts.maxAge - 0;

      if (!isNaN(maxAge)) {
        opts.expires = new Date(Date.now() + maxAge);
        opts.maxAge = Math.floor(maxAge / 1000);
      }
    }

    if (opts.path == null) {
      opts.path = "/";
    }

    this.append("Set-Cookie", cookie.serialize(name, String(val), opts));

    return this;
  }

  clearCookie(name: string, options?: TsED.SetCookieOpts) {
    const opts = {path: "/", ...options, expires: new Date(1)};
    delete opts.maxAge;
    return this.cookie(name, "", opts);
  }

  redirect(status: number, path: string) {
    this.statusCode = status;
    this.set("location", path);
  }

  location(path: string) {
    this.set("location", path);
  }

  get(key: string) {
    return this.headers[key.toLowerCase()];
  }

  getHeaders() {
    return this.headers;
  }

  set(key: string, value: any) {
    this.headers[key.toLowerCase()] = value;
    return this;
  }

  setHeader(key: string, value: any) {
    this.headers[key.toLowerCase()] = value;
    return this;
  }

  send(data: any) {
    this.data = data;
  }

  json(data: any) {
    this.data = data;
  }

  write(chunk: any) {
    this.emit("data", chunk);
  }

  end(data: any) {
    data !== undefined && (this.data = data);

    this.emit("end");
  }
}

import {isPrimitive, nameOf, Type} from "@tsed/core";
import {Provider} from "@tsed/di";
import type {PlatformParamsCallback} from "@tsed/platform-params";
import {concatPath} from "@tsed/schema";

import {PlatformHandlerMetadata} from "./PlatformHandlerMetadata.js";
import type {PlatformRouter} from "./PlatformRouter.js";
import {SinglePathType} from "./SinglePathType.js";

export interface PlatformLayerOptions extends Record<string, any> {
  token?: Type<any>;
}

export interface PlatformLayerProps {
  parent: PlatformLayer;
  provider: Provider;
  path: SinglePathType;
  basePath: SinglePathType;
  method: string;
  handlers: any[];
  router: PlatformRouter;
  opts: PlatformLayerOptions;
}

export class PlatformLayer {
  public provider!: Provider;
  public path: SinglePathType = "";
  public method!: string;
  public handlers: PlatformHandlerMetadata[] = [];
  public router?: PlatformRouter;
  public opts: PlatformLayerOptions = {};

  public layers: PlatformLayer[] = [];

  public parent?: PlatformLayer;
  basePath: SinglePathType = "";
  #args!: PlatformParamsCallback[];

  constructor(props: Partial<PlatformLayerProps> = {}) {
    Object.assign(this, props);

    this.layers = this.layers.map((layer) => {
      return new PlatformLayer({
        ...layer,
        parent: this
      });
    });
  }

  set(args: PlatformParamsCallback[]) {
    this.#args = args;
  }

  getArgs(withPath?: true): [SinglePathType, ...PlatformParamsCallback[]];
  getArgs(withPath: false): PlatformParamsCallback[];
  getArgs(withPath = true) {
    return [withPath ? this.path : null, ...this.#args].filter(Boolean);
  }

  isProvider() {
    return !!this.provider;
  }

  inspect() {
    return {
      basePath: this.getBasePath(),
      path: this.path,
      method: this.method,
      handlers: this.handlers.map((item: any) => String(item)),
      opts: Object.entries(this.opts).reduce((obj, [key, value]) => {
        return {
          ...obj,
          [key]: isPrimitive(value) ? value : nameOf(value)
        };
      }, {})
    };
  }

  getBasePath(): string {
    return concatPath(this.parent?.getBasePath(), this.basePath);
  }

  setLayers(layers: PlatformLayer[]) {
    this.layers = layers.map((layer) => {
      return new PlatformLayer({
        ...layer,
        parent: this
      });
    });
  }
}

import type {ConnectionOptions} from "node:tls";

import {MongoDBContainer, StartedMongoDBContainer} from "@testcontainers/mongodb";
import type {ConnectOptions} from "mongoose";

declare global {
  namespace NodeJS {
    interface Global {
      TEST_CONTAINER_MONGO: StartedMongoDBContainer | null;
    }
  }
}

const KEY = "TEST_CONTAINER_MONGO";

// @ts-ignore
global[KEY] = null;

function getEnvironment<T>(key: string): T | null {
  // @ts-ignore
  return global[key];
}

function setEnvironment(key: string, environment: unknown) {
  // @ts-ignore
  global[key] = environment;
}

function createMongoContainer(image = "mongo:6.0.1") {
  return new MongoDBContainer(image).start();
}

export async function startMongoServer(image?: string) {
  // await stopMockServer()
  const container = getEnvironment<StartedMongoDBContainer>(KEY) || (await createMongoContainer(image));

  setEnvironment(KEY, container);

  process.env.MONGO_URL = container.getConnectionString();

  return {
    container,
    url: process.env.MONGO_URL
  };
}

export async function stopMongoServer() {
  const container = getEnvironment<StartedMongoDBContainer>(KEY);

  process.stdout.write("Stopping mongo server\n");
  if (container) {
    await container.stop();
  }
}

export function getMongoUrl(): string {
  return process.env.MONGO_URL as string;
}

export function getMongoConnectionOptions(
  id: string = "",
  opts: ConnectOptions = {}
): {
  id: string;
  url: string;
  connectionOptions: ConnectOptions;
} {
  const seed = Math.floor(Math.random() * 10000);
  const {dbName = "db-test", ...otherOpts} = opts;
  const url = `${getMongoUrl()}/${dbName}-${seed}`;

  return {
    id,
    url,
    connectionOptions: {
      directConnection: true,
      ...otherOpts
    } satisfies ConnectOptions
  };
}

export function getMongoConnectionsOptions(opts: ConnectionOptions = {}) {
  return [getMongoConnectionOptions("default", opts)];
}

import {promisify} from "node:util";

import {Inject, Injectable, InjectorService} from "@tsed/di";
import {Request} from "express";

import {FormioHooks} from "../domain/FormioHooks.js";
import {FormioService} from "./FormioService.js";

@Injectable()
export class FormioHooksService {
  @Inject()
  protected injector!: InjectorService;

  @Inject(FormioService)
  protected formio!: FormioService;

  get settings(): (req: Request, cb: Function) => void {
    return this.formio.hook.settings;
  }

  get invoke() {
    return this.formio.hook.invoke;
  }

  get alter(): (event: string, ...args: any[]) => any {
    return this.formio.hook.alter;
  }

  get alterAsync(): (event: string, ...args: any[]) => Promise<any> {
    return promisify(this.alter);
  }

  getHooks(): FormioHooks {
    return {
      alter: this.getHooksProvider("alter"),
      on: this.getHooksProvider("on")
    };
  }

  protected getProviders(type: "alter" | "on") {
    return this.injector.getProviders(`formio:${type}`);
  }

  protected getHooksProvider(type: "alter" | "on") {
    return this.bindHooks(type, this.createHooks(type));
  }

  protected bindHooks(type: "alter" | "on", hooks: Record<string, Function[]>) {
    return Object.entries(hooks).reduce((newHooks, [key, pool]) => {
      const wrap = (input: any, ...args: any[]): any => {
        let last: any;

        for (const fn of pool) {
          const result = fn(input, ...args);

          if (type === "alter") {
            input = result;
          } else {
            last = result;
          }
        }

        return type === "alter" ? input : last;
      };

      return {
        ...newHooks,
        [key]: wrap
      };
    }, {});
  }

  private createHooks(type: "alter" | "on") {
    return this.getProviders(type).reduce<Record<string, Function[]>>((hooks, provider) => {
      const instance = this.injector.invoke<any>(provider.token);
      const name = provider.store.get(`formio:${type}:name`);
      const pool: Function[] = hooks[name] || [];

      const hook = (...args: any[]) =>
        instance[type === "alter" ? "transform" : "on"](
          ...args.map((input: any) => {
            return input && input.$ctx ? input.$ctx : input;
          })
        );

      return {
        ...hooks,
        [name]: ([] as Function[]).concat(pool, hook)
      };
    }, {});
  }
}

#!/usr/bin/env ts-node
import fs from "fs-extra";
import {globby} from "globby";
import {join} from "node:path";

function resolveConfig() {
  return [
    join(process.cwd(), ".barrelsby.json"),
    join(process.cwd(), ".barrels.json")
  ].find((path) => {
    return fs.existsSync(path);
  });
}

function getConfig() {
  const configPath = resolveConfig();

  if (!configPath) {
    return {};
  }

  return fs.readJSON(configPath, "utf8");
}

async function cleanIndex(cwd, excluded) {
  const patterns = [
    "**/index.ts",
    ...excluded
  ];

  const files = await globby(patterns, {
    cwd: cwd
  });

  return Promise.all(files.map((file) => fs.unlink(join(cwd, file))));
}

async function build() {
  const {
    directory = ["./src"],
    exclude = ["**/__mock__", "**/__mocks__", "**/*.spec.ts", "**/*.benchmark.ts"],
    delete: shouldDelete
  } = await getConfig();
  const excluded = exclude
    .map((path) => `!${path}`)
    .concat(directory.map((path) => `!${path}/index.ts`));

  const promises = directory
    .map(async (directory) => {
      const baseIndex = join(process.cwd(), directory);

      // if (shouldDelete) {
      //   await cleanIndex(directory, excluded);
      // }

      const files = await globby([
        "**/*.ts",
        "!index.ts",
        ...excluded
      ], {
        cwd: directory
      });

      const exports = files
        .sort((a, b) => a.localeCompare(b))
        .map((file) => {
          return `export * from "./${file.replace(".ts", ".js")}";`;
        });

      const content = [
        "/**",
        " * @file Automatically generated by @tsed/barrels.",
        " */",
        ...exports
      ];

      await fs.writeFile(join(baseIndex, "index.ts"), content.join("\n") + "\n", {encoding: "utf8"});
    });

  await Promise.all(promises);
}


await build();
